from openai import OpenAI
import tiktoken

client = OpenAI()
encoding = tiktoken.encoding_for_model('gpt-4o')

def check_thread_context_limit(thread_id: str, model: str = 'gpt-4o', warning_threshold: int = 100000) -> dict:
    messages = client.beta.threads.messages.list(thread_id=thread_id)
    total_tokens = 0

    for msg in messages.data:
        # Content tokens
        if msg.content:
            for block in msg.content:
                if block.type == 'text':
                    total_tokens += len(encoding.encode(block.text.value))
        # Tool output tokens
        if msg.tool_outputs:
            for output in msg.tool_outputs:
                total_tokens += len(encoding.encode(output['body']))

    limit = 128000 if 'gpt-4o' in model else 8192
    usage_pct = (total_tokens / limit) * 100

    return {
        'total_tokens': total_tokens,
        'limit': limit,
        'usage_pct': usage_pct,
        'over_limit': total_tokens > limit,
        'needs_cleanup': usage_pct > warning_threshold
    }

import OpenAI from 'openai';

const openai = new OpenAI();

export async function analyzeThreadBloat(threadId: string): Promise<{ bloated: boolean; score: number }> {
  const messages = await openai.beta.threads.messages.list(threadId);

  let codeTokens = 0;
  let fileTokens = 0;
  let totalMessages = 0;
  let recentMessages = 0;

  for (const msg of messages.data) {
    totalMessages++;
    if (Date.now() - new Date(msg.created_at * 1000).getTime() < 24 * 60 * 60 * 1000) {
      recentMessages++;
    }

    // Count code interpreter and file heavy messages
    if (msg.tool_outputs?.some(t => t.type === 'code_interpreter')) {
      codeTokens += 2000; // Estimate
    }
    if (msg.annotations?.some(a => a.type === 'file_citation')) {
      fileTokens += 1500;
    }
  }

  const bloatScore = (codeTokens + fileTokens) / totalMessages + (totalMessages - recentMessages) * 10;

  return {
    bloated: bloatScore > 5000 || totalMessages > 100,
    score: bloatScore
  };
}

