import OpenAI from 'openai';

const openai = new OpenAI();

export async function dynamicContextRun(threadId: string, assistantId: string) {
  // Check current thread token usage
  const threadInfo = await checkThreadTokenUsage(threadId);

  let model = 'gpt-4o-mini';
  if (threadInfo.usagePct < 30) {
    model = 'gpt-4o-mini';  // Small context
  } else if (threadInfo.usagePct < 80) {
    model = 'gpt-4o';       // Medium context
  } else {
    // Large context - prune first
    await pruneThreadSafely(threadId);
    model = 'gpt-4o';
  }

  const run = await openai.beta.threads.runs.create(threadId, {
    assistant_id: assistantId,
    model,
    instructions: `Context usage: ${Math.round(threadInfo.usagePct)}%. Be concise.`
  });

  return run;
}

async function checkThreadTokenUsage(threadId: string) {
  const messages = await openai.beta.threads.messages.list(threadId);
  // Simplified token estimation
  const tokenEstimate = messages.data.reduce((sum, msg) => {
    return sum + (msg.content?.[0]?.text?.value?.length || 0) / 4;
  }, 0);

  return {
    usagePct: Math.min((tokenEstimate / 128000) * 100, 100),
    totalTokens: tokenEstimate
  };
}

